class HybridWebViewActivity : ComponentActivity() {

    private lateinit var webView: WebView
    private lateinit var bridge: NativeBridge
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraImageUri: Uri? = null

    private val permissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestMultiplePermissions()) { result ->
            bridge.onPermissionsResult(result)
        }

    private val fileChooserLauncher =
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val callback = filePathCallback ?: return@registerForActivityResult
            val uris = when {
                result.resultCode != Activity.RESULT_OK -> null
                result.data?.clipData != null -> {
                    val clipData = result.data!!.clipData!!
                    Array(clipData.itemCount) { i -> clipData.getItemAt(i).uri }
                }
                result.data?.data != null -> arrayOf(result.data!!.data!!)
                cameraImageUri != null -> arrayOf(cameraImageUri!!)
                else -> null
            }
            callback.onReceiveValue(uris)
            filePathCallback = null
            cameraImageUri = null
        }

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        webView = WebView(this)
        setContentView(webView)

        bridge = NativeBridge(
            activity = this,
            webView = webView,
            permissionRequester = { permissions -> permissionLauncher.launch(permissions) }
        )

        configureWebView(webView)

        if (savedInstanceState != null) {
            webView.restoreState(savedInstanceState)
        } else {
            val url = intent.getStringExtra(EXTRA_URL) ?: DEFAULT_URL
            webView.loadUrl(url)
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun configureWebView(webView: WebView) {
        val settings = webView.settings
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = true
        settings.databaseEnabled = true
        settings.allowFileAccess = true
        settings.allowContentAccess = true
        settings.mediaPlaybackRequiresUserGesture = false
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        settings.mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
        settings.javaScriptCanOpenWindowsAutomatically = true
        settings.setSupportMultipleWindows(true)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            settings.safeBrowsingEnabled = true
        }

        if (WebViewFeature.isFeatureSupported(WebViewFeature.ALGORITHMIC_DARKENING)) {
            WebSettingsCompat.setAlgorithmicDarkeningAllowed(settings, true)
        }

        webView.isVerticalScrollBarEnabled = false
        webView.isHorizontalScrollBarEnabled = false
        webView.addJavascriptInterface(bridge, JS_BRIDGE_NAME)

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val uri = request?.url ?: return false
                return handleExternalSchemes(uri)
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.grant(request.resources)
            }

            override fun onCreateWindow(
                view: WebView?,
                isDialog: Boolean,
                isUserGesture: Boolean,
                resultMsg: Message?
            ): Boolean {
                val transport = resultMsg?.obj as? WebView.WebViewTransport ?: return false
                val tempWebView = WebView(this@HybridWebViewActivity)
                tempWebView.webViewClient = object : WebViewClient() {
                    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                        val uri = request?.url ?: return false
                        return handleExternalSchemes(uri)
                    }
                }
                transport.webView = tempWebView
                resultMsg.sendToTarget()
                return true
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@HybridWebViewActivity.filePathCallback?.onReceiveValue(null)
                this@HybridWebViewActivity.filePathCallback = filePathCallback

                val chooserIntent = buildFileChooserIntent(fileChooserParams)
                return try {
                    fileChooserLauncher.launch(chooserIntent)
                    true
                } catch (_: Exception) {
                    this@HybridWebViewActivity.filePathCallback = null
                    false
                }
            }
        }
    }

    private fun buildFileChooserIntent(params: WebChromeClient.FileChooserParams?): Intent {
        val contentIntent = Intent(Intent.ACTION_GET_CONTENT).apply {
            addCategory(Intent.CATEGORY_OPENABLE)
            type = params?.acceptTypes?.firstOrNull()?.takeIf { it.isNotBlank() } ?: "*/*"
            putExtra(Intent.EXTRA_ALLOW_MULTIPLE, params?.mode == WebChromeClient.FileChooserParams.MODE_OPEN_MULTIPLE)
        }

        val intents = mutableListOf<Intent>()
        if (hasCameraPermission()) {
            createImageUri()?.let { uri ->
                cameraImageUri = uri
                intents += Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                    putExtra(MediaStore.EXTRA_OUTPUT, uri)
                    addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
                    addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
                }
            }
        }

        return Intent(Intent.ACTION_CHOOSER).apply {
            putExtra(Intent.EXTRA_INTENT, contentIntent)
            putExtra(Intent.EXTRA_INITIAL_INTENTS, intents.toTypedArray())
            putExtra(Intent.EXTRA_TITLE, "Select File")
        }
    }

    private fun createImageUri(): Uri? {
        return try {
            val fileName = "IMG_${SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())}.jpg"
            val values = android.content.ContentValues().apply {
                put(MediaStore.Images.Media.DISPLAY_NAME, fileName)
                put(MediaStore.Images.Media.MIME_TYPE, "image/jpeg")
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                    put(MediaStore.Images.Media.RELATIVE_PATH, Environment.DIRECTORY_PICTURES)
                }
            }
            contentResolver.insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, values)
        } catch (_: Exception) {
            null
        }
    }

    private fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED
    }

    private fun handleExternalSchemes(uri: Uri): Boolean {
        val scheme = uri.scheme?.lowercase(Locale.US) ?: return false
        return when (scheme) {
            "http", "https" -> false
            else -> {
                runCatching {
                    startActivity(Intent(Intent.ACTION_VIEW, uri))
                }
                true
            }
        }
    }

    override fun onSaveInstanceState(outState: Bundle) {
        webView.saveState(outState)
        super.onSaveInstanceState(outState)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) webView.goBack() else super.onBackPressed()
    }

    override fun onDestroy() {
        webView.removeJavascriptInterface(JS_BRIDGE_NAME)
        webView.destroy()
        super.onDestroy()
    }

    companion object {
        const val EXTRA_URL = "extra_url"
        const val DEFAULT_URL = "https://example.com"
        const val JS_BRIDGE_NAME = "NativeBridge"

        fun intent(context: Context, url: String = DEFAULT_URL): Intent {
            return Intent(context, HybridWebViewActivity::class.java).putExtra(EXTRA_URL, url)
        }
    }
}

class NativeBridge(
    private val activity: ComponentActivity,
    private val webView: WebView,
    private val permissionRequester: (Array<String>) -> Unit
) {
    private val prefs: SharedPreferences =
        activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)

    private var pendingPermissionAction: String? = null

    @JavascriptInterface
    fun cameraAccess(callbackId: String) {
        activity.runOnUiThread {
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
                dispatchSuccess(callbackId, JSONObject().put("granted", true))
            } else {
                pendingPermissionAction = callbackId
                permissionRequester(arrayOf(Manifest.permission.CAMERA))
            }
        }
    }

    @JavascriptInterface
    fun storageSet(key: String, value: String, callbackId: String) {
        prefs.edit().putString(key, value).apply()
        dispatchSuccess(callbackId, JSONObject().put("key", key).put("value", value))
    }

    @JavascriptInterface
    fun storageGet(key: String, callbackId: String) {
        val value = prefs.getString(key, null)
        dispatchSuccess(callbackId, JSONObject().put("key", key).put("value", value))
    }

    @JavascriptInterface
    fun storageRemove(key: String, callbackId: String) {
        prefs.edit().remove(key).apply()
        dispatchSuccess(callbackId, JSONObject().put("key", key).put("removed", true))
    }

    @JavascriptInterface
    fun storageClear(callbackId: String) {
        prefs.edit().clear().apply()
        dispatchSuccess(callbackId, JSONObject().put("cleared", true))
    }

    @JavascriptInterface
    fun pushGetToken(callbackId: String) {
        dispatchSuccess(callbackId, JSONObject().put("token", "PUSH_TOKEN_PLACEHOLDER"))
    }

    @JavascriptInterface
    fun pushSubscribe(topic: String, callbackId: String) {
        dispatchSuccess(callbackId, JSONObject().put("topic", topic).put("subscribed", true))
    }

    @JavascriptInterface
    fun pushUnsubscribe(topic: String, callbackId: String) {
        dispatchSuccess(callbackId, JSONObject().put("topic", topic).put("subscribed", false))
    }

    fun onPermissionsResult(result: Map<String, Boolean>) {
        val callbackId = pendingPermissionAction ?: return
        pendingPermissionAction = null
        val granted = result[Manifest.permission.CAMERA] == true
        if (granted) {
            dispatchSuccess(callbackId, JSONObject().put("granted", true))
        } else {
            dispatchError(callbackId, "CAMERA_PERMISSION_DENIED")
        }
    }

    private fun dispatchSuccess(callbackId: String, data: JSONObject) {
        dispatchToJs(
            JSONObject()
                .put("callbackId", callbackId)
                .put("success", true)
                .put("data", data)
        )
    }

    private fun dispatchError(callbackId: String, error: String) {
        dispatchToJs(
            JSONObject()
                .put("callbackId", callbackId)
                .put("success", false)
                .put("error", error)
        )
    }

    private fun dispatchToJs(payload: JSONObject) {
        val script = """
            window.HybridNative&&window.HybridNative.onNativeResult&&window.HybridNative.onNativeResult(${JSONObject.quote(payload.toString())});
        """.trimIndent()
        activity.runOnUiThread {
            webView.evaluateJavascript(script, null)
        }
    }
}